with open("/root/books/webapp/books.json") as f:
    books = json.load(f)

max_id = max(b["id"] for b in books)
print(f"Max ID before: {max_id}")

existing_ids = {b["id"] for b in books}
added = []
for b in new_books:
    if b["id"] in existing_ids:
        print(f"SKIP: ID {b['id']} already exists")
    else:
        books.append(b)
        added.append(b["id"])

issues = []
for b in new_books:
    for i, t in enumerate(b.get("thoughts", [])):
        total = len(t["title"]) + len(t["example"])
        if total < 600 or total > 800:
            issues.append(f"Book {b['id']} t{i}: {total} chars")

if issues:
    print("LENGTH ISSUES (will fix separately):")
    for iss in issues:
        print(" ", iss)

with open("/root/books/webapp/books.json", "w", encoding="utf-8") as f:
    json.dump(books, f, ensure_ascii=False, separators=(",", ":"))
print(f"SAVED — added: {added}")
